(function(w){"use strict";const ID="unit-price";function compute(x){const p1=Number(x.p1),q1=Number(x.q1),p2=Number(x.p2),q2=Number(x.q2);if([p1,q1,p2,q2].some(v=>!Number.isFinite(v)||v<=0))return{error:"두 상품의 가격과 용량을 0보다 큰 숫자로 입력해 주세요."};const u1=p1/q1,u2=p2/q2;return{u1,u2,winner:u1===u2?0:(u1<u2?1:2),saving:Math.abs(u1-u2)/Math.max(u1,u2)*100}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div><h3>상품 A</h3><div class="hm-calc-field"><label>가격</label><input class="hm-calc-input" inputmode="numeric"></div><div class="hm-calc-field"><label>용량·수량</label><input class="hm-calc-input" inputmode="decimal"></div></div><div><h3>상품 B</h3><div class="hm-calc-field"><label>가격</label><input class="hm-calc-input" inputmode="numeric"></div><div class="hm-calc-field"><label>용량·수량</label><input class="hm-calc-input" inputmode="decimal"></div></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">단가 비교하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const ins=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({p1:api.parseNumber(ins[0].value),q1:api.parseNumber(ins[1].value),p2:api.parseNumber(ins[2].value),q2:api.parseNumber(ins[3].value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");const title=r.winner===0?"두 상품의 단가가 같습니다.":`상품 ${r.winner===1?"A":"B"}가 더 저렴합니다.`;api.setResult(res,api.resultCard(title,r.winner===0?"동일 단가":api.formatNumber(r.saving,2)+"% 절약",`<dl><dt>상품 A 단가</dt><dd>${api.formatNumber(r.u1,4)}원 / 단위</dd><dt>상품 B 단가</dt><dd>${api.formatNumber(r.u2,4)}원 / 단위</dd></dl>`));});}w.HM_CALC.register(ID,{compute,render});})(window);
